{
  "name": "LIHEAP (Low-Income Home Energy Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly income limits (2025): 1 person $3,967; 2 people $5,187; 3 people $6,408; 4 people $7,629; 5 people $8,849; 6 people $10,070. Annual guidelines at 75% state median (e.g., 1 person $48,711; 2 $63,699; 3 $78,688; 4 $93,676; 5 $108,664; 6 $123,653; 7 $126,463; 8 $129,274) may apply for related emergency aid. Everyone at the address counts as household, including roommates on same utility bill.[1][4]",
    "asset_limits": "No asset limit.[1]",
    "other_requirements": ["Must reside in New Hampshire.", "Renters and homeowners eligible.", "Priority for elderly, disabled, families with young children under 6.", "Available for heating season (fall/winter); crisis for emergencies like shutoffs or broken furnace. Cooling not offered.[1][2][5]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Heating assistance: $94 minimum to $2,177 maximum per household, paid directly to heating vendor. Winter crisis: up to $2,177. No summer crisis. Varies by income, household size, fuel type. Does not count as income for other programs.[1][2][5]",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": [
      "Contact regional Community Action Agency by phone for appointment (e.g., Belknap/Merrimack: 603-223-0043; Rockingham: 603-436-3896; Strafford: 603-435-2500).",
      "In-person at local Community Action offices (open M-F 8:30am-4:30pm year-round). Pre-applications for priority (elderly/disabled/young kids) after July 1; others after Sept 1 for 2025-2026 season. Applications start ~July 30, 2025, until funds exhausted.[2][3][5]",
      "Mail or other routes via local agency."
    ],
    "processing_time": "Not specified; apply early as funds limited.",
    "waitlist": "No waitlist mentioned; funding awarded until depleted.",
    "forms": ["Pre-application for priority groups; full application via intake interview.[5]"],
    "documents": ["Income proof (pay stubs, benefits statements), household size info, heating bills/fuel type, ID. List provided after initial phone intake.[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; serves all NH counties via regional agencies.",
    "regional_variations": "Administered by regional Community Action Agencies with different offices and phone numbers; no benefit differences noted.",
    "offices_or_providers": ["Belknap/Merrimack (Concord: 603-223-0043)", "Rockingham (Portsmouth: 603-436-3896)", "Strafford (Dover: 603-435-2500)", "Other regions via local Community Action Partnership of NH (CAPNH).[3][5]"]
  },
  "official_source": "https://www.energy.nh.gov/ (NH Department of Energy); local via CAPNH at https://www.caphr.org/services/fuel-assistance",
  "gotchas": [
    "Household includes all at address on same utility (even non-sharing roommates).[1]",
    "Not year-round; heating seasonal (Oct onward), crisis only for emergencies.[1][2]",
    "Apply early (July 30, 2025 start); funds run out.[2][5]",
    "Priority pre-apps July 1 for elderly/disabled/kids under 6; others Sept 1.[5]",
    "Separate from state emergency aid (60-75% median) or HEA weatherization.[4][6]"
  ],
  "data_shape_notes": "Administered regionally by Community Action Agencies; benefits scale by household size, income, fuel type, priority (elderly/disabled prioritized); seasonal with early funding exhaustion."
}

{
  "name": "SHIP (State Health Insurance Assistance Program)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers seeking health insurance counseling[2][3][4][5][6].",
    "asset_limits": "No asset limits apply[2][4][6].",
    "other_requirements": ["Must be a Medicare beneficiary or family member/caregiver with questions about Medicare or related insurance; services are free and confidential with no personal information shared unless requested[2][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized health insurance counseling, information and printed materials, referrals to agencies; covers Medicare Part A/B, Part D, Medigap, Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, and other programs; helps understand benefits, compare options, avoid overpayment[2][4][5][6].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-634-9412 (toll-free, 8am-4pm or by appointment)[3][5]", "Website: http://www.servicelink.nh.gov/medicare/index.htm[5]", "In-person: Appointments via ServiceLink Resource Center, NH DHHS Bureau of Elderly & Adult Services, 105 Pleasant St., Gov. Gallan State Office Park S., Concord NH 03301-3857[5]"],
    "processing_time": "Immediate counseling available by phone or appointment; no formal processing as it's direct service[2][5].",
    "waitlist": null,
    "forms": ["No specific forms required; contact to schedule counseling[2]"],
    "documents": ["No documents needed for initial counseling; may request Medicare card or insurance details if discussing specific enrollment[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["Administered statewide by ServiceLink Resource Center (NH DHHS Bureau of Elderly & Adult Services in Concord); local access via phone/website statewide[3][5]"]
  },
  "official_source": "http://www.servicelink.nh.gov/medicare/index.htm",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling and education, no direct payment or services; does not handle enrollments itself but refers/guides; people confuse with Medicare Savings Programs (which SHIP counselors explain but have separate eligibility like income up to $1,660 single/$2,239 couple for QI/SLMB-135 and assets $9,090 single/$13,630 couple)[1][2][4]", "Requires trained counselors/volunteers; availability by appointment outside 8am-4pm[5]", "Focuses on Medicare navigation, not general Medicaid or long-term care applications (though refers)[2][6]"],
  "data_shape_notes": "no income/asset test; counseling-only service statewide via single provider (ServiceLink); refers to programs with limits like MSPs but SHIP itself is universal for Medicare-related questions"
}

