    "forms": ["No specific form names/numbers listed"],
    "documents": ["Proof of age", "Proof of income (to verify ≤125% FPL)", "Proof of unemployment", "Proof of NH residency", "Work authorization documents"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "NH resident required",
    "regional_variations": "Operated by providers like Operation ABLE covering NH service areas; potential differences in host sites, wait times, or local minimum wage application by region, but no explicit variations detailed",
    "offices_or_providers": ["Operation ABLE (primary NH SCSEP provider spotlighted for NH service areas)"]
  },
  "official_source": "https://www.dol.gov/agencies/eta/seniors",
  "gotchas": ["Enrollment priority given first to veterans/qualified spouses, then over 65, disabled, low literacy, limited English, rural residents, homeless/at-risk, low prospects, or prior American Job Center users - may delay non-priority applicants[2]", "Program is temporary training bridge to unsubsidized jobs, not permanent employment", "Must be actively unemployed and seeking skills refresh; not for current workers", "Income calculated as family income at 125% FPL - check current guidelines as they update yearly"],
